-- Populate item descriptions from frontend/items.json
UPDATE items SET description = CASE id
    WHEN 1001 THEN '<mainText><stats><attention>25</attention> Move Speed</stats><br><br></mainText>'
    WHEN 1004 THEN '<mainText><stats><attention>50%</attention> Base Mana Regen</stats><br><br></mainText>'
    WHEN 1006 THEN '<mainText><stats><attention>100%</attention> Base Health Regen</stats><br><br></mainText>'
    WHEN 1011 THEN '<mainText><stats><attention>350</attention> Health</stats><br><br></mainText>'
    WHEN 1018 THEN '<mainText><stats><attention>15%</attention> Critical Strike Chance</stats><br><br></mainText>'
    WHEN 1026 THEN '<mainText><stats><attention>45</attention> Ability Power</stats><br><br></mainText>'
    WHEN 1027 THEN '<mainText><stats><attention>300</attention> Mana</stats><br><br></mainText>'
    WHEN 1028 THEN '<mainText><stats><attention>150</attention> Health</stats><br><br></mainText>'
    WHEN 1029 THEN '<mainText><stats><attention>15</attention> Armor</stats><br><br></mainText>'
    WHEN 1031 THEN '<mainText><stats><attention>40</attention> Armor</stats><br><br></mainText>'
    WHEN 1033 THEN '<mainText><stats><attention>20</attention> Magic Resist</stats><br><br></mainText>'
    WHEN 1035 THEN '<mainText><stats></stats><br><br><passive>7%</passive> Omnivamp against jungle monsters<br><li><passive>Sear:</passive> Damaging jungle monsters burns them for <magicDamage> magic damage</magicDamage> over 5 seconds.<li><passive>Challenging Path:</passive> Smiting 5 times <status>consumes</status> this item and upgrades your Smite to <attention>Challenging Smite</attention>, increasing its damage to monsters to <trueDamage>900</trueDamage> and damage to minions to <trueDamage>500 +10% target max Health</trueDamage>. Challenging Smite marks champions for 4 seconds. Damaging a marked champion deals an additional <trueDamage> true damage</trueDamage> to them over 2.5 seconds. You take 10% reduced damage from marked champions.<li><passive>Huntsman:</passive> Killing large jungle monsters grants bonus experience.<li><passive>Recoup:</passive> Regen up to <scaleMana> Mana</scaleMana> (based on missing mana) per second when in the jungle or river. <br><br><rules><status>Consuming</status> this item grants all item effects permanently and increases Smite damage to monsters. If you have gained more gold from minions than jungle monsters, gold and experience from minions is heavily reduced. Healing is not reduced on AoE attacks. If two levels behind the average champion level of the game, monster kills grant bonus experience. </rules><br><rules>Only attacks and abilities apply Challenging Smite''s burn</rules></mainText>'
    WHEN 1036 THEN '<mainText><stats><attention>10</attention> Attack Damage</stats><br><br></mainText>'
    WHEN 1037 THEN '<mainText><stats><attention>25</attention> Attack Damage</stats><br><br></mainText>'
    WHEN 1038 THEN '<mainText><stats><attention>40</attention> Attack Damage</stats><br><br></mainText>'
    WHEN 1039 THEN '<mainText><stats></stats><br><br><passive>7%</passive> Omnivamp against jungle monsters<br><li><passive>Sear:</passive> Damaging jungle monsters burns them for <magicDamage> magic damage</magicDamage> over 5 seconds.<li><passive>Chilling Path:</passive> Smiting 5 times <status>consumes</status> this item and upgrades your Smite to <attention>Chilling Smite</attention>, increasing its damage to monsters to <trueDamage>900</trueDamage> and damage to minions to <trueDamage>500 +10% target max Health</trueDamage>. Chilling Smite deals <trueDamage> true damage</trueDamage> to champions and steals <speed>20% of their Move Speed</speed> for 2 seconds.<li><passive>Huntsman:</passive> Killing large jungle monsters grants bonus experience.<li><passive>Recoup:</passive> Regen up to <scaleMana> Mana</scaleMana> (based on missing mana) per second when in the jungle or river. <br><br><rules><status>Consuming</status> this item grants all item effects permanently and increases Smite damage to monsters. If you have gained more gold from minions than jungle monsters, gold and experience from minions is heavily reduced. Healing is not reduced on AoE attacks. If two levels behind the average champion level of the game, monster kills grant bonus experience. </rules></mainText>'
    WHEN 1040 THEN '<mainText><stats></stats><br><br><passive>8%</passive> Omnivamp against jungle monsters<br><li><passive>Sear:</passive> Damaging jungle monsters burns them for <magicDamage> magic damage</magicDamage> over 5 seconds.<li><passive>Auto Path:</passive> Smiting 5 times <status>consumes</status> this item and upgrades your Attack-Smite, increasing its damage to monsters to <trueDamage>900</trueDamage>.<li><passive>Huntsman:</passive> Killing large jungle monsters grants bonus experience.<li><passive>Recoup:</passive> Regen up to <scaleMana> Mana</scaleMana> (based on missing mana) per second when in the jungle or river. <br><br><rules><status>Consuming</status> this item grants all item effects permanently and increases Smite damage to monsters. If you have gained more gold from minions than jungle monsters, gold and experience from minions is heavily reduced. Healing is not reduced on AoE attacks. If two levels behind the average champion level of the game, monster kills grant bonus experience. </rules></mainText>'
    WHEN 1042 THEN '<mainText><stats><attention>10%</attention> Attack Speed</stats><br><br></mainText>'
    WHEN 1043 THEN '<mainText><stats><attention>15%</attention> Attack Speed</stats><br><br><passive>Sting</passive><br>Attacks deal <physicalDamage>15 bonus physical damage</physicalDamage> <OnHit>On-Hit</OnHit>.</mainText>'
    WHEN 1052 THEN '<mainText><stats><attention>20</attention> Ability Power</stats><br><br></mainText>'
    WHEN 1053 THEN '<mainText><stats><attention>15</attention> Attack Damage<br><attention>7%</attention> Life Steal</stats><br><br></mainText>'
    WHEN 1054 THEN '<mainText><stats><attention>110</attention> Health</stats><br><br><passive>Enduring Focus</passive><br>Restore <healing>4 Health</healing> every 5 seconds. <br>After taking damage from a champion, restore <healing>Health</healing> over 8 seconds.<br><br><passive>Helping Hand</passive><br>Attacks deal <physicalDamage>5 bonus physical damage</physicalDamage> to minions.</mainText>'
    WHEN 1055 THEN '<mainText><stats><attention>10</attention> Attack Damage<br><attention>80</attention> Health<br><attention>2.5%</attention> Omnivamp</stats><br><br></mainText>'
    WHEN 1056 THEN '<mainText><stats><attention>18</attention> Ability Power<br><attention>90</attention> Health</stats><br><br><passive>Drain</passive><br>Restore <scaleMana>1 Mana</scaleMana> every second, increased to <scaleMana>2 Mana</scaleMana> per second for 5 seconds after dealing damage to an enemy champion. If you can''t gain Mana, <healing>heal for 45%</healing> of this value instead.<br><br><passive>Helping Hand</passive><br>Attacks deal <physicalDamage>5 bonus physical damage</physicalDamage> to minions.</mainText>'
    WHEN 1057 THEN '<mainText><stats><attention>45</attention> Magic Resist</stats><br><br></mainText>'
    WHEN 1058 THEN '<mainText><stats><attention>65</attention> Ability Power</stats><br><br></mainText>'
    WHEN 1082 THEN '<mainText><stats><attention>15</attention> Ability Power<br><attention>50</attention> Health</stats><br><br><passive>Glory</passive><br><keyword>Takedowns</keyword> grant <passive>Glory</passive>, up to 10. 5 <passive>Glory</passive> is lost on death.<br>Gain <scaleAP>4 Ability Power</scaleAP> per <passive>Glory</passive>.</mainText>'
    WHEN 1083 THEN '<mainText><stats><attention>7</attention> Attack Damage</stats><br><br><passive>Reap</passive><br>Restore <healing>3 Health</healing> <OnHit>On-Hit</OnHit>.<br>Killing minions grants <gold>1 gold</gold>, up to <gold>100</gold>. Reaching the limit grants another <gold>350 gold</gold>.<br></mainText>'
    WHEN 1086 THEN '<mainText><stats><attention>8</attention> Attack Damage<br><attention>15%</attention> Attack Speed<br><attention>1.5%</attention> Omnivamp</stats><br><br></mainText>'
    WHEN 1101 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#DD2E2E''>Scorchclaw</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and periodically imbues your next Attack or Ability to burn enemies and <status>Slow</status> them. Killing large monsters readies this immediately.</mainText>'
    WHEN 1102 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#38A8E8''>Gustwalker</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and grants <speed>Move Speed</speed> upon entering brush, increased when killing large monsters.</mainText>'
    WHEN 1103 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#1CA935''>Mosstomper</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and grants a Shield while out of combat and after killing large monsters.</mainText>'
    WHEN 1104 THEN '<mainText><stats></stats><br><br><br><br><active>Active - Consume:</active> Crush the Eye of the Herald, begining the ritual to summon Rift Herald. You may click the Rift Herald after it has summoned to control how it charges. This control effect can be done once when it is summoned, and once each time a nearby enemy structure dies.</mainText>'
    WHEN 1105 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#1CA935''>Mosstomper</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and grants a Shield while out of combat and after killing large monsters.</mainText>'
    WHEN 1106 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#38A8E8''>Gustwalker</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and grants <speed>Move Speed</speed> upon entering brush, increased when killing large monsters.</mainText>'
    WHEN 1107 THEN '<mainText><stats></stats><br><br><passive>Jungle Companions</passive><br>Summon a <font color=''#DD2E2E''>Scorchclaw</font> that assists you against monsters.<br><br>The companion grows as you hunt monsters, empowering your <spellName>Smite</spellName>. When fully grown, it completes your Jungle Quest and periodically imbues your next Attack or Ability to burn enemies and <status>Slow</status> them. Killing large monsters readies this immediately.</mainText>'
    WHEN 1111 THEN '<mainText><stats><attention>25%</attention> Attack Speed<br><attention>100</attention> Move Speed<br><attention>10</attention> Ability Haste<br><attention>12</attention> Magic Penetration<br><attention>25</attention> Armor<br><attention>20</attention> Magic Resist<br><attention>30%</attention> Tenacity</stats><br><br><passive>Jarvan One</passive><br>Gives you stats and passives from all boots.<br><br><b>Requires Augment: <prismatic>Quest: Sneakerhead</prismatic></b></mainText>'
    WHEN 1120 THEN '<mainText><stats><attention>140</attention> Health<br><attention>10</attention> Armor<br><attention>10</attention> Magic Resist</stats><br><br><passive>Helping Hand</passive><br>Attacks deal <physicalDamage>5 bonus physical damage</physicalDamage> to minions.</mainText>'
    WHEN 1200 THEN '<mainText><stats></stats><br><br>Takedown champions, minions, towers, plates, and epic monsters to complete your quest. Earn points much faster in top lane!<br><br><font color = ''#00FF00''>Rewards</font><br>• Teleport as a 3rd Summoner Spell<br>• Flat bonus experience, more experience from all sources, and increased level cap</mainText>'
    WHEN 1201 THEN '<mainText><stats></stats><br><br>Takedown champions, minions, towers, plates, and epic monsters to complete your quest. Earn points much faster in mid lane!<br><br><font color = ''#00FF00''>Rewards</font><br>• Upgrade boots to tier 3<br>• Increased Bonus AD and AP</mainText>'
    WHEN 1202 THEN '<mainText><stats></stats><br><br>Takedown champions, minions, towers, plates, and epic monsters to complete your quest. Earn points much faster in bot lane!<br><br><font color = ''#00FF00''>Rewards</font><br>• Gold imediately and Increased gold from Minion kills and champion takedowns<br>• A bonus item slot for your boots</mainText>'
    WHEN 1203 THEN '<mainText><stats></stats><br><br>Control wards always go into your role quest slot. Upgrade your <font color = ''#DBA12C''>Support Item</font> to complete your quest. Earn points by damaging enemy champions or turrets, or killing minions while near an ally. Earn points much faster in bot Lane!<br><br><font color = ''#00FF00''>Rewards</font><br>• Upgraded support item<br>• Discounted control wards</mainText>'
    WHEN 1204 THEN '<mainText><stats></stats><br><br>Upgrade your <font color = ''#DBA12C''>Jungle Pet</font> to complete your quest. Earn points by killing jungle monsters.<br><br><font color = ''#00FF00''>Rewards</font><br>• Upgraded jungle pet and Smite<br>• Increased gold and XP from large monsters<br>• Bonus movement speed in the jungle</mainText>'
    WHEN 1206 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• Upgrade boots to tier 3<br>• +8% bonus Attack Damage and Ability Power</mainText>'
    WHEN 1207 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• +300immediately and Boots move to a 7th slot, freeing up your inventory for 6 items<br>• +2from Minion kills<br>• +40from Champion takedowns</mainText>'
    WHEN 1208 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• A new slot for control wards<br>• Discounted control wards<br>• Bounty of Worlds item</mainText>'
    WHEN 1209 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• Upgraded Smite and evolve jungle pet to <font color = ''#0B6623''>Mosstomper</font><br>• Increased gold and XP from large monsters<br>• Bonus movement speed in the jungle</mainText>'
    WHEN 1220 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• Extra Action - Teleport: After channeling for 0 seconds, become <keyword>Untargetable</keyword> and travel to target allied structure, minion, or ward.<br>• Flat bonus experience, more experience from all sources, and an increased level cap</mainText>'
    WHEN 1221 THEN '<mainText><stats></stats><br><br><font color = ''#00FF00''>Rewards</font><br>• Enhance your Teleport with a large max-health shield on use<br>• Flat bonus experience, more experience from all sources, and an increased level cap</mainText>'
    WHEN 1222 THEN '<mainText><stats></stats><br><br>Takedown champions, minions, towers, plates, and epic monsters to complete your quest. Earn points much faster in top lane!<br><br><font color = ''#00FF00''>Rewards</font><br>• Enhance your Teleport with a large max-health shield on use<br>• Flat bonus experience, more experience from all sources, and increased level cap</mainText>'
    WHEN 123430 THEN '<mainText><stats><attention>55</attention> Ability Power<br><attention>10</attention> Ability Haste<br><attention>25%</attention> Critical Strike Chance<br><attention>4%</attention> Move Speed</stats><br><br><passive>Wrath and Ruin</passive><br>On spell cast, gain <attention>2.5% Critical Strike Chance</attention> for 6 seconds, stacking up to 20%.<br><br><passive>Salvage the Wreckage</passive><br>Your spells have a chance equal to your <attention>Critical Strike Chance</attention> to grant you or your targeted ally a <shield>shield for </shield> for 3s.</mainText>'
    WHEN 124011 THEN '<mainText><stats><attention>45</attention> Ability Power<br><attention>200</attention> Health<br><attention>12%</attention> Heal and Shield Power<br><attention>15</attention> Ability Haste</stats><br><br><passive>Effervescence</passive><br>Gain +<attackSpeed>1.2% Attack Speed</attackSpeed> for every <healing>1% Heal and Shield Power</healing> you have. <br><br><passive>Peppermint</passive><br><OnHit>On-Hit</OnHit>, <healing>heal the lowest health</healing> ally champion near you for , prioritizing lower health allies.</mainText>'
    WHEN 126697 THEN '<mainText><stats><attention>55</attention> Attack Damage<br><attention>18</attention> Lethality<br><attention>10</attention> Ability Haste</stats><br><br><passive>Eminence</passive><br>Gain temporary AD based on champion kills on kill.</mainText>'
    WHEN 1501 THEN '<mainText><stats></stats><br><br></mainText>'
    WHEN 1502 THEN '<mainText><stats></stats><br><br><mainText><unique>Reinforced</unique><br>Turrets take 80% reduced damage, including True Damage, when no enemy Lane Minions or Rift Herald are nearby.<br><br><unique>Melee Weakness</unique><br>Turrets take 20% increased damage from melee Champions.</mainText></mainText>'
    WHEN 1505 THEN '<mainText><stats></stats><br><br><mainText><unique>Reinforced</unique><br>Turrets take 80% reduced damage, including True Damage, when no enemy Lane Minions or Rift Herald are nearby.<br><br><unique>Melee Weakness</unique><br>Turrets take 20% increased damage from melee Champions.<br><br><unique>Regeneration</unique><br>Inhibitor turrets have health regeneration but cannot regenerate past their current segment at 30%, 75%, and 100% health.</mainText></mainText>'
    WHEN 1506 THEN '<mainText><stats></stats><br><br><mainText><unique>Reinforced</unique><br>Turrets take 80% reduced damage, including True Damage, when no enemy Lane Minions or Rift Herald are nearby.<br><br><unique>Melee Weakness</unique><br>Turrets take 20% increased damage from melee Champions.<br><br><unique>Regeneration</unique><br>Inhibitor turrets have health regeneration but cannot regenerate past their current segment at 30%, 75%, and 100% health.</mainText></mainText>'
    WHEN 2001 THEN 'Teleports your champion to the Summoning Platform after 8 seconds. Any damage taken will cancel the teleport.'
    WHEN 2003 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Restores <healing>120 Health</healing> over 15 seconds.</mainText>'
    WHEN 2010 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Eat the biscuit to restore <healing>Health</healing> over 5 seconds, increased based on missing health. Consuming or selling a biscuit permanently grants <healing>30 maximum Health</healing>. </mainText>'
    WHEN 2015 THEN '<mainText><stats><attention>15</attention> Attack Damage</stats><br><br><passive>Jolt</passive><br><keyword>Energized Attacks</keyword> deal an additional <magicDamage>50 magic damage</magicDamage>.</mainText>'
    WHEN 2019 THEN '<mainText><stats><attention>15</attention> Attack Damage<br><attention>30</attention> Armor</stats><br><br></mainText>'
    WHEN 2020 THEN '<mainText><stats><attention>25</attention> Attack Damage<br><attention>10</attention> Ability Haste<br><attention>5</attention> Lethality</stats><br><br></mainText>'
    WHEN 2021 THEN '<mainText><stats><attention>15</attention> Attack Damage<br><attention>250</attention> Health</stats><br><br></mainText>'
    WHEN 2022 THEN '<mainText><stats><attention>5</attention> Ability Haste</stats><br><br></mainText>'
    WHEN 2031 THEN '<mainText><stats></stats><br><br><active>Active</active> (2 charges)<br>Restores <healing>100 Health</healing> over 12 seconds. <br>Refills upon visiting the shop.</mainText>'
    WHEN 2033 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Consumes a charge to restore <healing>100 Health</healing> and <scaleMana>75 Mana</scaleMana> over 12 seconds. During this time, damaging Abilities and Attacks burn enemy champions for <magicDamage>15 (20 if you cannot gain Mana) magic damage</magicDamage> over 3 seconds. Holds up to 3 charges and refills upon visiting the shop.<br><br><rules>Corrupting damage is reduced to 50% when triggered by area of effect or periodic damage.</rules></mainText>'
    WHEN 2049 THEN '<mainText><stats><attention>15%</attention> Heal and Shield Power<br><attention>20</attention> Ability Power<br><attention>20</attention> Ability Haste</stats><br><br><passive>Recovery</passive><br>Restores <scaleMana>10 Mana</scaleMana> every 5 seconds. If you can''t gain mana, restores <healing>3 Health</healing> instead.</mainText>'
    WHEN 2050 THEN '<mainText><stats><attention>300</attention> Health<br><attention>35</attention> Ability Power<br><attention>15</attention> Ability Haste</stats><br><br></mainText>'
    WHEN 2051 THEN '<mainText><stats><attention>150</attention> Health</stats><br><br><br><li><passive>Recovery:</passive> Restores <healing>20 Health</healing> every 5 seconds.<li><passive>Undaunted:</passive> Blocks 15 damage from attacks and spells from champions (25% effectiveness vs. damage over time abilities).<br></mainText>'
    WHEN 2052 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Serves a scrumptious scoop to a nearby Poro, causing it to grow in size.<br><br><flavorText>This savory blend of free-range, grass-fed Avarosan game hens and organic, non-ZMO Freljordian herbs contains the essential nutrients necessary to keep your Poro purring with pleasure.<br><br>All proceeds will be donated towards fighting Noxian animal cruelty. </flavorText></mainText>'
    WHEN 2055 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Places a Control Ward that grants vision and reveals enemy Stealth Wards, traps and <keywordStealth>Camouflaged</keywordStealth> enemies.</mainText>'
    WHEN 2056 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Places a Stealth Ward on the ground that lasts 60 seconds, is <keywordStealth>Invisible</keywordStealth> to enemies but grants your team vision of the surrounding area. </mainText>'
    WHEN 2065 THEN '<mainText><stats><attention>50</attention> Ability Power<br><attention>15</attention> Ability Haste<br><attention>4%</attention> Move Speed<br><attention>125%</attention> Base Mana Regen</stats><br><br><active>Inspiring Speech</active><br>Grant nearby allies <speed>30% Move Speed</speed> for 4 seconds.</mainText>'
    WHEN 2138 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Grants <scaleHealth>300 Health</scaleHealth>, 25% Tenacity and increased size for 3 minutes. While active, you leave a path behind that boosts allied champions'' <speed>Move Speed by 15%</speed>.</mainText>'
    WHEN 2139 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Grants <scaleAP>50 Ability Power</scaleAP> and <scaleMana>15% Mana Regen</scaleMana> for 3 minutes. While active, damaging a champion or turret deals <trueDamage>25 bonus true damage</trueDamage> (5s against champions).</mainText>'
    WHEN 2140 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Grants <scaleAD>30 Attack Damage</scaleAD> and <lifeSteal>12% Physical Vamp</lifeSteal> against champions for 3 minutes.</mainText>'
    WHEN 2141 THEN '<mainText><stats></stats><br><br><rules>Helps you get on a head.</rules><active>Active - Consume:</active> This juice does nothing.<br></mainText>'
    WHEN 2142 THEN '<mainText><stats></stats><br><br><br><br><rules>Juices do not stack with themselves, but you can have multiple different ones active.</rules><active>Active - Consume:</active> Automatically activates on Combat Start. Drink to gain <scaleAP>30+ 10% bonus Ability Power</scaleAP> or <scaleAD>18+ 10% bonus Attack Damage</scaleAD> for the next round.<br><br><flavorText>Made with 100% real cherries. Warning: May cause imbiber to deal tons of damage.</flavorText></mainText>'
    WHEN 2143 THEN '<mainText><stats></stats><br><br><br><br><rules>Juices do not stack with themselves, but you can have multiple different ones active.</rules><active>Active - Consume:</active> Automatically activates on Combat Start. Drink to gain <healing>300+ 10% Health</healing> for the next round.<br><br><flavorText>Our specially formulated veggie blend is proven to harden your skin to resist even the strongest attacks!</flavorText></mainText>'
    WHEN 2144 THEN '<mainText><stats></stats><br><br><br><br><rules>Juices do not stack with themselves, but you can have multiple different ones active.</rules><active>Active - Consume:</active> Automatically activates on Combat Start. Drink to gain <speed>20+ 15% Ability Haste</speed> for the next round.<br><br><flavorText>For people who gotta go FAST. Made with lightning. REAL lightning!</flavorText></mainText>'
    WHEN 2145 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Roll to gain 1 additional reroll.<br><br><flavorText>For when skill isn''t enough.</flavorText></mainText>'
    WHEN 2146 THEN '<mainText><stats></stats><br><br><active>Active - Consume:</active> Roll to gain 5 additional rerolls.<br><br><flavorText>For when skill isn''t enough.</flavorText></mainText>'
