    WHEN 2152 THEN '<mainText><stats></stats><br><br><active>Consume</active><br>Grants 25 Adaptive Force for 60 seconds. </mainText>'
    WHEN 2161 THEN '<mainText><stats></stats><br><br>Drink to permanently gain <scaleAP>20+ 3% bonus Ability Power</scaleAP> or <scaleAD>12+ 3% bonus Attack Damage</scaleAD>. And a hat!<br><br><flavorText>Made with 100% real cherries. Warning: May cause imbiber to deal tons of damage.</flavorText></mainText>'
    WHEN 2162 THEN '<mainText><stats></stats><br><br>Drink to permanently gain <healing>200+ 3% Health</healing>. And a hat!<br><br><flavorText>Our specially formulated veggie blend is proven to harden your skin to resist even the strongest attacks!</flavorText></mainText>'
