    WHEN 9279 THEN '<mainText><stats></stats><br><br>Fires a cone of projectiles with bonus crit chance in a random direction. Projectiles pierce on crit.<br><br><status>Evolve:</status> Crit Chance<br><br><rules>Damage, Ability Haste, Crit Chance, Projectile Count</rules></mainText>'
